Ast2Asg::operator()(ast::JumpStatementContext* ctx)
{
  std::cerr << "DEBUG: JumpStatement start" << std::endl;
  if (ctx->Return()) {
    auto ret = make<ReturnStmt>();
    ret->func = mCurrentFunc;
    if (auto p = ctx->expression()) {
      std::cerr << "DEBUG: processing return expression" << std::endl;
      ret->expr = self(p);
      std::cerr << "DEBUG: return expression done" << std::endl;
    }
    return ret;
  }

